// Recebe msg.payload = { Temperatura: x, Orvalho: y, ... }
let p = msg.payload || {};
let T = Number(p.Temperatura);
let Td = Number(p.Orvalho);
if (isNaN(T) || isNaN(Td)) {
    node.warn('Temperatura ou Orvalho ausente em payload');
    return null;
}
let diff = Math.abs(T - Td);
let prob = 0;
if (diff <= 0.5) prob = 100;
else if (diff < 3) prob = Math.round(100 - ((diff - 0.5) / 2.5) * 100);
else prob = 0;
msg.payload = prob; // valor que vai pro gauge
msg.topic = 'prob_chuva';
msg.diff = diff;
msg.info = `ΔT=${diff.toFixed(2)}°C (T=${T} Td=${Td})`;
return msg;

