let cmd = msg.payload;
let tkey = 'timer_y0';
let timekey = 'time_y0';

function stopTimer(){
    let old = flow.get(tkey);
    if(old) clearTimeout(old);
    flow.set(tkey,null);
}

if(cmd === 'AUTO_ON'){

    stopTimer();

    let tempo = flow.get(timekey) || 1;

    let t = setTimeout(()=>{

        node.send([
            {payload:{y0:false}},
            {payload:'AUTO_OFF'}
        ]);

        flow.set(tkey,null);

    }, tempo * 1000);

    flow.set(tkey,t);

    return [
        {payload:{y0:true}},
        {payload:'AUTO_ON'}
    ];
}

