    stopTimer();

    return [
        {payload:{y0:false}},
        {payload:'AUTO_OFF'}
    ];
}

if(cmd === 'MANUAL_ON'){

    stopTimer();

    return [
        {payload:{y0:true}},
        null
    ];
}

if(cmd === 'MANUAL_OFF'){

    stopTimer();

    return [
        {payload:{y0:false}},
        null
    ];
}

return null;

